	  manuscript_analyzer_title: { en: "Manuscript Analyzer", it: "Analizzatore manoscritto", es: "Analizador de manuscritos", fr: "Analyseur de manuscrit", de: "Manuskript-Analyse" },
	  manuscript_analyzer_desc: { en: "Upload a TXT, Markdown, or DOCX book. Scriptora scores the manuscript and prepares a rewrite-ready project with editorial advice per chapter.", it: "Carica un libro TXT, Markdown o DOCX. Scriptora valuta il manoscritto e prepara un progetto pronto per la riscrittura con consigli editoriali per capitolo.", es: "Sube un libro TXT, Markdown o DOCX. Scriptora evalúa el manuscrito y prepara un proyecto listo para reescritura con consejos editoriales por capítulo.", fr: "Importez un livre TXT, Markdown ou DOCX. Scriptora note le manuscrit et prépare un projet prêt à réécrire avec des conseils éditoriaux par chapitre.", de: "Lade ein TXT-, Markdown- oder DOCX-Buch hoch. Scriptora bewertet das Manuskript und erstellt ein Projekt mit Kapitelhinweisen für die Überarbeitung." },
